import EditObject from './EditObject'
import NoneSelected from './NoneSelected'

function Sidebar({ newObject, doubleClickedObj }) {
    return (
        <aside className="sidebar">
            <button onClick={newObject}>Add object</button>
            {doubleClickedObj ? <EditObject /> : <></>}
        </aside>
    );
}

export default Sidebar;
